let attempts = 0;

const value = await retryNetworkCall(async () => {
  attempts++;

  if (attempts < 3) {
    throw new Error("temporary failure");
  }

  return "ok";
});

assert.equal(value, "ok");
assert.equal(attempts, 3);
```

